mitigation.description:
This is a false positive. All of our endpoints are secured by default fallback policy, so unless it explicitely has AllowUnauthenticated it will always check for a token. 

    public static IServiceCollection AddApiAuthorization(this IServiceCollection services)
    {

        services.AddAuthorization(options =>
       {
           options.AddPolicy(AuthConstants.Policies.CoE,
               policy =>
               {
                   policy.RequireAuthenticatedUser();
                   policy.RequireClaim(AuthConstants.Claims.groups, AuthConstants.Roles.CoE);
               });

           options.FallbackPolicy = new AuthorizationPolicyBuilder()
               .RequireAuthenticatedUser()
               .Build();
       });
        return services;
    }

